import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
// ✅ FIXED: Imported the correct API utilities along with getUserData
import { adminGetAllUsers, adminDeleteTargetUser, getUserData } from '../utils/api';

function AdminPanel({ user }) {
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const navigate = useNavigate();

  // Fetch the users list on panel load
  useEffect(() => {
    // Note: If you store the admin name as 'name' or 'username' inside your App.js state, 
    // make sure this conditional match aligns with your state model properties.
    if (!user || user.role !== "admin") {
      navigate("/login");
    } else {
      // ✅ FIXED: Changed from getAllUsers() to adminGetAllUsers()
      adminGetAllUsers()
        .then(data => setUsers(data))
        .catch(err => console.error("Error fetching users dashboard records:", err));
    }
  }, [user, navigate]);

  if (!user || user.role !== "admin") {
    return null; 
  }

  // View specific user profiles
  function viewUserDetails(username) {
    // ✅ FIXED: Using the imported getUserData method to query profiles by username
    getUserData(username)
      .then(data => setSelectedUser(data))
      .catch(err => console.error("Error gathering profile data:", err));
  }

  // ✅ NEW: Added delete handler to connect with your adminDeleteTargetUser backend route
  function handleDeleteUser(username) {
    if (window.confirm(`Are you absolutely sure you want to remove user "${username}" from the database?`)) {
      adminDeleteTargetUser(username)
        .then(res => {
          if (res.success) {
            alert(res.message);
            // Refresh local state list instantly without full page reloads
            setUsers(prevUsers => prevUsers.filter(u => u.username !== username));
            if (selectedUser && selectedUser.username === username) {
              setSelectedUser(null);
            }
          } else {
            alert(res.error || "Failed to drop target record.");
          }
        })
        .catch(err => console.error(err));
    }
  }

  return (
    <div style={{ padding: "30px", maxWidth: "1000px", margin: "auto" }}>
      <h2>Admin Panel Workspace Area</h2>
      <p style={{ backgroundColor: "#f8f9fa", padding: "10px", borderRadius: "4px", display: "inline-block" }}>
        <strong>Active Session Admin:</strong> {user.name || user.username}
      </p>

      <table style={{ width: "100%", borderCollapse: "collapse", marginTop: "20px" }}>
        <thead>
          <tr style={{ backgroundColor: "#007bff", color: "#fff", textAlign: "left" }}>
            <th style={{ padding: "12px", border: "1px solid #ddd" }}>Username</th>
            <th style={{ padding: "12px", border: "1px solid #ddd" }}>Email</th>
            <th style={{ padding: "12px", border: "1px solid #ddd" }}>Role Tier</th>
            <th style={{ padding: "12px", border: "1px solid #ddd" }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.length === 0 ? (
            <tr>
              <td colSpan="4" style={{ padding: "15px", textAlign: "center", color: "#666" }}>No registered user data found.</td>
            </tr>
          ) : (
            users.map(u => (
              // ✅ FIXED: Using unique u.username as keys since Firestore tracks records by lowercase username IDs
              <tr key={u.username} style={{ borderBottom: "1px solid #ddd" }}>
                <td style={{ padding: "12px", border: "1px solid #ddd" }}>{u.username}</td>
                <td style={{ padding: "12px", border: "1px solid #ddd" }}>{u.email}</td>
                <td style={{ padding: "12px", border: "1px solid #ddd" }}>
                  <span style={{ 
                    padding: "4px 8px", 
                    borderRadius: "4px", 
                    fontSize: "12px", 
                    backgroundColor: u.role === "admin" ? "#f8d7da" : "#d4edda",
                    color: u.role === "admin" ? "#721c24" : "#155724"
                  }}>
                    {u.role}
                  </span>
                </td>
                <td style={{ padding: "12px", border: "1px solid #ddd" }}>
                  <button 
                    onClick={() => viewUserDetails(u.username)}
                    style={{ marginRight: "10px", padding: "6px 12px", cursor: "pointer", background: "#17a2b8", color: "#fff", border: "none", borderRadius: "4px" }}
                  >
                    Inspect Details
                  </button>
                  <button 
                    onClick={() => handleDeleteUser(u.username)}
                    style={{ padding: "6px 12px", cursor: "pointer", background: "#dc3545", color: "#fff", border: "none", borderRadius: "4px" }}
                  >
                    Delete User
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      {selectedUser && (
        <div style={{ marginTop: "30px", border: "1px solid #bcbebf", padding: "20px", borderRadius: "8px", backgroundColor: "#f9fbfd" }}>
          <h3 style={{ marginTop: "0", color: "#333" }}>📋 User Inspector Profile</h3>
          <p><strong>Username ID:</strong> {selectedUser.username}</p>
          <p><strong>Email Address:</strong> {selectedUser.email}</p>
          <p><strong>Account Security Status:</strong> {selectedUser.role}</p>
          <p><strong>Created Database Epoch Timestamp:</strong> {selectedUser.createdAt ? new Date(selectedUser.createdAt).toLocaleString() : "N/A"}</p>
          
          <button 
            onClick={() => setSelectedUser(null)}
            style={{ marginTop: "10px", padding: "6px 12px", cursor: "pointer", background: "#6c757d", color: "#fff", border: "none", borderRadius: "4px" }}
          >
            Close Inspector
          </button>
        </div>
      )}
    </div>
  );
}

export default AdminPanel;
